public class XRadioButtonsBooleanTriStateWidget extends XRadioButtonsWidget {   public static final WidgetId ID = WidgetId.XRadioButtonsBooleanTriStateWidget;   protected List<BooleanState> states = Arrays.asList(BooleanState.Yes, BooleanState.No, BooleanState.UnSet);   protected List<XRadioButtonWidget> buttons = new ArrayList<XRadioButtonWidget>();   protected BooleanState selected = BooleanState.UnSet;   public XRadioButtonsBooleanTriStateWidget() {      this(ID, "");   }   public XRadioButtonsBooleanTriStateWidget(String displayLabel) {      super(ID, displayLabel);   }   public XRadioButtonsBooleanTriStateWidget(WidgetId widgetId, String displayLabel) {      super(widgetId, displayLabel);   }   @Override   protected void createControls(Composite parent, int horizontalSpan) {      for (BooleanState state : states) {         XRadioButtonWidget button = addButton(state.name());         buttons.add(button);         button.setUseLabelFont(false);         button.setObject(state);         button.setSelected(state.equals(selected));         button.setObject(button);         button.addXModifiedListener(new XModifiedListener() {            @Override            public void widgetModified(XWidget widget) {               handleSelection(button);            }         });      }      super.createControls(parent, horizontalSpan);   }   protected void handleSelection(XRadioButtonWidget button) {      selected = BooleanState.valueOf(button.getLabel());      refresh();   }   public BooleanState getSelected() {      return selected;   }   public void setSelected(BooleanState state) {      for (XRadioButtonWidget button : buttons) {         if (button.getLabel().equals(state.name())) {            button.setSelected(true);            selected = state;         } else {            button.setSelected(false);         }      }      refresh();   }   @Override   public IStatus isValid() {      if (isRequiredEntry() && selected.isUnSet()) {         return new Status(IStatus.ERROR, Activator.PLUGIN_ID, getLabel() + " must have at least one selection.");      }      return Status.OK_STATUS;   }   @Override   public Object getData() {      return selected;   }}